        /// <param name="updateConversationRequest"></param>
        /// <returns>ApiResponse of Object(void)</returns>
        ApiResponse<Object> UpdateConversationWithHttpInfo(string conversationIdentifier, UpdateConversationRequest updateConversationRequest);
