        System.Threading.Tasks.Task<ApiResponse<List<SearchConnectionResponse>>> SearchConnectionWithHttpInfoAsync(SearchConnectionRequest searchConnectionRequest, System.Threading.CancellationToken cancellationToken = default(global::System.Threading.CancellationToken));
