        /// <returns>Task of ApiResponse</returns>
        System.Threading.Tasks.Task<ApiResponse<Object>> UpdateColumnSecurityRulesWithHttpInfoAsync(UpdateColumnSecurityRulesRequest updateColumnSecurityRulesRequest, System.Threading.CancellationToken cancellationToken = default(global::System.Threading.CancellationToken));
