        /// <summary>
        /// 
        /// </summary>
        /// <remarks>
        ///   Version: 26.7.0.cl or later   Uploads a custom font to the cluster-level or org-level font library. Cluster-level fonts are available as defaults for all orgs. Org-level fonts are only available within that org.  Requires &#x60;ADMINISTRATION&#x60; (**Can administer ThoughtSpot**) or &#x60;DEVELOPER&#x60; (**Has developer privilege**) privilege.  #### Usage guidelines  - Only **WOFF** and **WOFF2** font formats are accepted. TTF and OTF files are rejected with an error. - The &#x60;name&#x60; field must be unique within the target scope. Uploading a font with a name that already exists returns an error. - Set &#x60;scope&#x60; to &#x60;CLUSTER&#x60; to upload to the cluster-level library. Set &#x60;scope&#x60; to &#x60;ORG&#x60; (default) to upload to the authenticated user&#39;s org library. - &#x60;weight&#x60; defaults to &#x60;NORMAL&#x60; if omitted. Supported values: &#x60;NORMAL&#x60;, &#x60;LIGHT&#x60;, &#x60;BOLD&#x60;. - &#x60;style&#x60; defaults to &#x60;NORMAL&#x60; if omitted. Supported values: &#x60;NORMAL&#x60;, &#x60;ITALIC&#x60;, &#x60;OBLIQUE&#x60;. - &#x60;color&#x60; defaults to &#x60;#000000&#x60; (black) if omitted. Provide as a 6-digit hex string (e.g. &#x60;#333333&#x60;). - The uploaded font can be assigned to visualization areas using the &#x60;updateStyleCustomization&#x60; endpoint.      
        /// </remarks>
        /// <exception cref="ThoughtSpot.Client.Client.ApiException">Thrown when fails to make API call</exception>
        /// <param name="name">Display name for the font (e.g. \\\&quot;Acme Sans\\\&quot;). Must be unique within the target scope; returns an error if a font with this name already exists.</param>
        /// <param name="fileContent">Binary WOFF or WOFF2 font file to upload. Only WOFF and WOFF2 formats are accepted; TTF and OTF are rejected. The file is validated on upload.</param>
        /// <param name="scope">Scope of the font library to upload to. CLUSTER uploads to the cluster-level library, making the font available as a default for all orgs. ORG uploads to the authenticated user&#39;s org library. Defaults to ORG if omitted. (optional, default to ORG)</param>
        /// <param name="weight">Weight of the font. Supported values: NORMAL, LIGHT, BOLD. Defaults to NORMAL if omitted. (optional, default to NORMAL)</param>
        /// <param name="style">Style of the font. Supported values: NORMAL, ITALIC, OBLIQUE. Defaults to NORMAL if omitted. (optional, default to NORMAL)</param>
        /// <param name="color">Color of the font as a 6-digit hex string (e.g. \\\&quot;#333333\\\&quot;). Defaults to #000000 (black) if omitted. Returns an error if the value is malformed. (optional)</param>
        /// <param name="cancellationToken">Cancellation Token to cancel the request.</param>
        /// <returns>Task of StyleFontUploadData</returns>
        System.Threading.Tasks.Task<StyleFontUploadData> UploadStyleFontAsync(string name, FileParameter fileContent, string? scope = default(string?), string? weight = default(string?), string? style = default(string?), string? color = default(string?), System.Threading.CancellationToken cancellationToken = default(global::System.Threading.CancellationToken));

